// Her work item ID i\u00e7in ayr\u0131 bir n8n item \u00fcret (paralel i\u015fleme)
const payload = $json["body"];

if (!payload.missingWorkItemIds || payload.missingWorkItemIds.length === 0) {
  return [];
}

return payload.missingWorkItemIds.map(workItemId => ({
  json: {
    workItemId: Number(workItemId),
    versionId:    payload.versionId,
    azureOrg:     payload.azureOrg,
    azureProject: payload.azureProject,
    azurePat:     payload.azurePat,
    mcpServerUrl: payload.mcpServerUrl,
    backendUrl:   payload.backendUrl,
    token:        payload.token,
  }
}));

// MCP yanıtını release note DB formatına dönüştür (runOnceForAllItems)
const mcpItems  = $input.all();
const dataItems = $('DataPreparation').all();

const results = [];

for (let i = 0; i < mcpItems.length; i++) {
  const mcpResp = mcpItems[i].json;
  const ctx     = dataItems[i] ? dataItems[i].json : {};

  // MCP hata döndü veya boş geldi — bu item'ı atla
  const hasError = !mcpResp
    || mcpResp.error
    || mcpResp.detail
    || (mcpResp.statusCode && mcpResp.statusCode >= 400)
    || !mcpResp.release_notes;

  if (hasError) {
    console.log('MCP hata döndü, work item atlanıyor:', ctx.workItemId, JSON.stringify(mcpResp).slice(0, 300));
    continue;
  }

  const rn = mcpResp.release_notes?.releaseNote ?? {};
  const businessTitle = (rn.business?.title   ?? '').trim() || ('Work Item #' + ctx.workItemId);
  const businessDesc  = (rn.business?.description  ?? '').trim();
  const technicalDesc = (rn.technical?.description ?? '').trim();

  const category = 'FEATURE';

  const parts = [];
  if (businessDesc)  parts.push(businessDesc);
  if (technicalDesc && technicalDesc !== businessDesc) {
    parts.push('---');
    parts.push(technicalDesc);
  }
  const description = parts.join('\n\n') || null;

  results.push({
    json: {
      productVersionId: ctx.versionId,
      workitemId:       String(ctx.workItemId),
      category,
      title:            businessTitle,
      description,
      isBreaking:       false,
      _backendUrl:      ctx.backendUrl,
      _token:           ctx.token,
    }
  });
}

return results;

// MCP 'changes' verisini SystemChange kayıtlarına dönüştür
// UI / API / TABLE kategorileri için ayrı ayrı işler
const mcpItems  = $('GenerateReleaseNoteMCP').all();
const dataItems = $('DataPreparation').all();

const typeMap = {
  deleted: 'BREAKING',
  added:   'FEATURE',
  updated: 'FEATURE',
};

const allChanges = [];

for (let i = 0; i < mcpItems.length; i++) {
  const mcpResp = mcpItems[i].json;
  const ctx     = dataItems[i] ? dataItems[i].json : {};

  if (!mcpResp || mcpResp.error || mcpResp.detail || !mcpResp.release_notes) {
    continue;
  }

  const changes    = mcpResp.release_notes.changes;
  if (!changes) continue;

  const versionId  = ctx.versionId;
  const workitemId = String(ctx.workItemId);

  // ── UI changes ──────────────────────────────────────────────
  for (const [operation, fields] of Object.entries(changes.ui || {})) {
    for (const f of (fields || [])) {
      const detail = `field: ${f.field}, type: ${f.type || ''}, label: ${f.label || ''}`;
      allChanges.push({
        productVersionId: versionId,
        workitemId,
        source:        'MCP',
        changeType:    typeMap[operation] || 'FEATURE',
        isBreaking:    operation === 'deleted',
        title:         `[UI] ${operation}: ${f.field}${f.label ? ' (' + f.label + ')' : ''}`,
        description:   detail,
        apiPath:       null,
        previousValue: operation === 'deleted' ? detail : (operation === 'updated' ? JSON.stringify(f.changes) : null),
        newValue:      operation === 'added'   ? detail : (operation === 'updated' ? JSON.stringify(f.changes) : null),
      });
    }
  }

  // ── API changes ──────────────────────────────────────────────
  for (const [operation, endpoints] of Object.entries(changes.api || {})) {
    for (const e of (endpoints || [])) {
      const endpointLabel = `${e.httpMethod} ${e.path}`;
      let description = endpointLabel;
      let previousValue = null;
      let newValue      = null;

      if (operation === 'added') {
        description = `Request: ${JSON.stringify(e.requestModel || {})}, Response: ${JSON.stringify(e.responseModel || {})}`;
        newValue    = description;
      } else if (operation === 'deleted') {
        description   = `Request: ${JSON.stringify(e.requestModel || {})}, Response: ${JSON.stringify(e.responseModel || {})}`;
        previousValue = description;
      } else if (operation === 'updated') {
        const reqChg = e.requestModelChanges  ? JSON.stringify(e.requestModelChanges)  : null;
        const resChg = e.responseModelChanges ? JSON.stringify(e.responseModelChanges) : null;
        description   = [reqChg && `RequestChanges: ${reqChg}`, resChg && `ResponseChanges: ${resChg}`].filter(Boolean).join(' | ');
        previousValue = reqChg;
        newValue      = resChg;
      }

      allChanges.push({
        productVersionId: versionId,
        workitemId,
        source:        'MCP',
        changeType:    typeMap[operation] || 'FEATURE',
        isBreaking:    operation === 'deleted',
        title:         `[API] ${operation}: ${endpointLabel}`,
        description:   description || null,
        apiPath:       endpointLabel,
        previousValue,
        newValue,
      });
    }
  }

  // ── TABLE changes ────────────────────────────────────────────
  for (const [operation, columns] of Object.entries(changes.table || {})) {
    for (const c of (columns || [])) {
      const columnLabel = `${c.table}.${c.column}`;
      let description   = `table: ${c.table}, column: ${c.column}, type: ${c.dataType || ''}`;
      let previousValue = null;
      let newValue      = null;

      if (operation === 'added') {
        description += `, nullable: ${c.nullable ?? true}, default: ${c.default ?? 'null'}`;
        newValue    = description;
      } else if (operation === 'deleted') {
        previousValue = description;
      } else if (operation === 'updated') {
        description   = `Changes: ${JSON.stringify(c.changes || {})}`;
        previousValue = JSON.stringify(c.changes || {});
        newValue      = JSON.stringify(c.changes || {});
      }

      allChanges.push({
        productVersionId: versionId,
        workitemId,
        source:        'MCP',
        changeType:    typeMap[operation] || 'FEATURE',
        isBreaking:    operation === 'deleted',
        title:         `[TABLE] ${operation}: ${columnLabel}`,
        description:   description || null,
        apiPath:       null,
        previousValue,
        newValue,
      });
    }
  }
}

console.log(`SaveChanges: ${allChanges.length} sistem degisikligi bulk olarak kaydedilecek`);

if (allChanges.length === 0) {
  return [];
}

const ctx0 = dataItems[0] ? dataItems[0].json : {};
return [{
  json: {
    items:       allChanges,
    _backendUrl: ctx0.backendUrl,
    _token:      ctx0.token,
    _count:      allChanges.length,
  }
}];
